"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["22278"],{74242(i){i.exports=JSON.parse('{"tag":{"label":"specialization","permalink":"/sysanalyst-kb.github.io/docs/tags/specialization","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":7,"items":[{"id":"specialization/ai-analyst-intro","title":"AI-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u0438 \u0440\u043E\u043B\u044C","description":"AI-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u044D\u0442\u043E \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A, \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439\u0441\u044F \u043D\u0430 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0430\u0445 \u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u0445 \u0441 \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u043E\u043C. \u041E\u043D \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u0441\u0431\u043E\u0440 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0439 \u043A ML-\u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u0430\u043C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044E \u0434\u0430\u043D\u043D\u044B\u0445, \u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u043A\u0443 \u043C\u0435\u0442\u0440\u0438\u043A \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u043C\u043E\u0434\u0435\u043B\u0438 \u0438 \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u0438\u0435 \u043E\u0436\u0438\u0434\u0430\u043D\u0438\u0439 \u043C\u0435\u0436\u0434\u0443 \u0431\u0438\u0437\u043D\u0435\u0441\u043E\u043C \u0438 Data Science \u043A\u043E\u043C\u0430\u043D\u0434\u043E\u0439.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ai-analyst-intro"},{"id":"specialization/ecommerce-retail-path","title":"E-commerce & Retail \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C","description":"E-commerce-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u043E\u043D\u043B\u0430\u0439\u043D-\u043F\u0440\u043E\u0434\u0430\u0436\u0430\u043C\u0438 Wildberries, Ozon, \u042F\u043D\u0434\u0435\u043A\u0441.\u041C\u0430\u0440\u043A\u0435\u0442, AliExpress.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-retail-path"},{"id":"specialization/fintech-analyst-path","title":"FinTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C","description":"FinTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A, \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u044E\u0449\u0438\u0439\u0441\u044F \u043D\u0430 \u0444\u0438\u043D\u0430\u043D\u0441\u043E\u0432\u044B\u0445 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0430\u0445: \u043F\u043B\u0430\u0442\u0435\u0436\u0430\u0445, \u0431\u0430\u043D\u043A\u0438\u043D\u0433\u0435, \u043A\u0440\u0435\u0434\u0438\u0442\u043E\u0432\u0430\u043D\u0438\u0438. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \xab\u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E\xbb SA, \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u0440\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u0438\u043A\u0443 (\u0426\u0411, KYC/AML, PCI DSS), \u043F\u043B\u0430\u0442\u0451\u0436\u043D\u044B\u0435 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B\u044B (ISO 8583, ISO 20022) \u0438 \u0431\u0443\u0445\u0433\u0430\u043B\u0442\u0435\u0440\u0441\u043A\u0438\u0439 \u0443\u0447\u0451\u0442 (double-entry ledger). \u042D\u0442\u043E \u043E\u0434\u043D\u0430 \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0432\u044B\u0441\u043E\u043A\u043E\u043E\u043F\u043B\u0430\u0447\u0438\u0432\u0430\u0435\u043C\u044B\u0445 \u043D\u0438\u0448 \u0434\u043B\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430.","permalink":"/sysanalyst-kb.github.io/docs/specialization/fintech-analyst-path"},{"id":"specialization/ba-vs-sa","title":"\u0411\u0438\u0437\u043D\u0435\u0441-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A vs \u0421\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A","description":"\u041E\u0434\u0438\u043D \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0447\u0430\u0441\u0442\u044B\u0445 \u0432\u043E\u043F\u0440\u043E\u0441\u043E\u0432 \u043E\u0442 \u043D\u043E\u0432\u0438\u0447\u043A\u043E\u0432: \xab\u0427\u0435\u043C \u0431\u0438\u0437\u043D\u0435\u0441-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A (BA) \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u043E\u0433\u043E \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 (SA)?\xbb \u0413\u0434\u0435 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0440\u0430\u0431\u043E\u0442\u0430 BA \u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0440\u0430\u0431\u043E\u0442\u0430 SA?","permalink":"/sysanalyst-kb.github.io/docs/specialization/ba-vs-sa"},{"id":"specialization/industry-analytics","title":"\u041E\u0442\u0440\u0430\u0441\u043B\u0435\u0432\u0430\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 (FinTech, Retail, Logistics)","description":"\u0421\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043E\u0431\u044B\u0447\u043D\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u043D\u0435 \u0432 \u0432\u0430\u043A\u0443\u0443\u043C\u0435, \u0430 \u0432 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0439 \u043E\u0442\u0440\u0430\u0441\u043B\u0438. \u0420\u0430\u0437\u043D\u044B\u0435 \u043E\u0442\u0440\u0430\u0441\u043B\u0438 \u0438\u043C\u0435\u044E\u0442 \u0440\u0430\u0437\u043D\u0443\u044E \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0443: \u0442\u0435\u0440\u043C\u0438\u043D\u043E\u043B\u043E\u0433\u0438\u044E, \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B, \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0441\u0438\u0441\u0442\u0435\u043C\u0435, \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044E.","permalink":"/sysanalyst-kb.github.io/docs/specialization/industry-analytics"},{"id":"specialization/data-analyst-path","title":"\u041F\u0443\u0442\u044C Data-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430","description":"Data-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A (\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u0430\u043D\u043D\u044B\u0445) \u2014 \u044D\u0442\u043E \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0441\u0442, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u0434\u0430\u043D\u043D\u044B\u043C\u0438: \u0441\u043E\u0431\u0438\u0440\u0430\u0435\u0442, \u043E\u0447\u0438\u0449\u0430\u0435\u0442, \u0430\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u0438 \u0432\u0438\u0437\u0443\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u043E\u0433\u043E \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430, \u0444\u043E\u043A\u0443\u0441 \u043D\u0435 \u043D\u0430 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u0445 \u043A \u0441\u0438\u0441\u0442\u0435\u043C\u0435, \u0430 \u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u0445 \u0438 \u0432\u044B\u0432\u043E\u0434\u0430\u0445 \u0438\u0437 \u043D\u0438\u0445.","permalink":"/sysanalyst-kb.github.io/docs/specialization/data-analyst-path"},{"id":"specialization/solution-architect-path","title":"\u041F\u0443\u0442\u044C Solution-\u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u043E\u0440\u0430","description":"Solution Architect (SArch) \u2014 \u044D\u0442\u043E \u0440\u043E\u043B\u044C, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u0431\u0438\u0437\u043D\u0435\u0441 \u0438 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E. Solution Architect \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B: \u0432\u044B\u0431\u043E\u0440 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0439, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438, \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0435 \u0441\u0442\u0438\u043B\u0438, \u043E\u0446\u0435\u043D\u043A\u0430 \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/solution-architect-path"}],"unlisted":false}}')}}]);